171	    // ------------------------------------------------------------
172	    // CASE 6: Failed to acquire create-lock -> triggers requeue and returns error
173	    // ------------------------------------------------------------
174	    @Test
175	    void testCreateLockFailedRequeue() {
176	        String existKey = RedisUtil.getExistKey(req);
177	        String lockKey =  RedisUtil.getEntityLockKey(Constants.RedisKeys.ENTITY_CREATE_LOCK_PREFIX, req);
178	
179	        when(entityCache.getCachedEntityId(existKey)).thenReturn(null);
180	        long ttl = Constants.RedisKeys.ENTITY_CREATE_LOCK_TTL;
181	        when(distributedLock.tryLock(lockKey, ttl)).thenReturn(false);
182	
183	        assertEquals(0, req.getRequeueCount());
184	
185	        StatusOr<Entity> result = orchestrator.process(req);
186	
187	        assertFalse(result.ok());
188	        assertEquals(Constants.BusinesCode.ACQUIRE_CREATE_LOCK_FAILURE,
189	                result.getStatus().getCode());
190	        assertEquals("create lock fail", result.getStatus().getMessage());
191	
192	        assertEquals(1, req.getRequeueCount());
193	
194	        // first delay = 2^0 * 2s = 2s = 2000 ms
195	        verify(redisDelayQueueUtil)
196	                .enqueueWithDelay(eq(req), eq(2000L));
197	
198	        verify(distributedLock).tryLock(lockKey, ttl);
199	
200	        verifyNoInteractions(entityService);
201	        verifyNoInteractions(newEntityHandler);
202	        verifyNoInteractions(cachedExistingEntityHandler);
203	        verifyNoInteractions(dbExistingEntityHandler);
204	
205	        verify(distributedLock, never()).unLock(anyString());
206	    }
