208	    @Test
209	    void testCreateLockFailure_ExceedMaxRetry_ShouldFailDirectly() {
210	        String existKey = RedisUtil.getExistKey(req);
211	        String lockKey = RedisUtil.getEntityLockKey(Constants.RedisKeys.ENTITY_CREATE_LOCK_PREFIX, req);
212	
213	        when(entityCache.getCachedEntityId(existKey)).thenReturn(null);
214	
215	        // retryCount reaches MAX_REQUEUE (5)
216	        req.setRequeueCount(5);
217	
218	        long ttl = Constants.RedisKeys.ENTITY_CREATE_LOCK_TTL;
219	        when(distributedLock.tryLock(lockKey, ttl)).thenReturn(false);
220	
221	        StatusOr<Entity> result = orchestrator.process(req);
222	
223	        assertFalse(result.ok());
224	        assertEquals(Constants.BusinesCode.ACQUIRE_CREATE_LOCK_FAILURE,
225	                result.getStatus().getCode());
226	        assertEquals("too many requeue for create lock",
227	                result.getStatus().getMessage());
228	
229	        // NO enqueue should happen
230	        verify(redisDelayQueueUtil, never()).enqueueWithDelay(any(), anyLong());
231	
232	        // NO producer
233	        verifyNoInteractions(redisDelayQueueUtil);
234	        verifyNoInteractions(entityService);
235	        verifyNoInteractions(newEntityHandler);
236	        verifyNoInteractions(cachedExistingEntityHandler);
237	        verifyNoInteractions(dbExistingEntityHandler);
238	    }
